entry.content:
@font-face {
  font-family: 'MapleMonoCN';
  src: url('../fonts/MapleMono-NF-CN-Regular.ttf') format('truetype');
  font-display: swap;
}

:root {
  --blog-accent: #2563eb;
  --blog-accent-soft: #dbeafe;
  --blog-border: #cbd5e1;
  --blog-surface: #ffffff;
  --blog-text: #1e293b;
  --blog-muted: #64748b;
}

body {
  background:
    radial-gradient(circle at top right, rgba(37, 99, 235, 0.12), transparent 24%),
    linear-gradient(180deg, #f8fafc 0%, #eff6ff 100%);
}

.index-card {
  border: 1px solid rgba(148, 163, 184, 0.18);
  border-radius: 24px;
  padding: 1rem;
  background: rgba(255, 255, 255, 0.82);
  backdrop-filter: blur(12px);
  box-shadow: 0 18px 50px rgba(15, 23, 42, 0.06);
}

.index-card img,
.index-img img {
  border-radius: 18px;
}

.post-content code,
.post-content pre,
code,
pre {
  font-family: 'MapleMonoCN', 'Consolas', monospace;
}

.post-meta,
.index-excerpt,
.post-content {
  color: var(--blog-text);
}

.project-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
  gap: 1.25rem;
}

.project-card {
  border: 1px solid rgba(148, 163, 184, 0.22);
  border-radius: 20px;
  padding: 1.5rem;
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.92), rgba(239, 246, 255, 0.88));
  box-shadow: 0 14px 32px rgba(15, 23, 42, 0.06);
}

.project-card h2 {
  margin-top: 0;
  margin-bottom: 0.75rem;
}

.project-card p,
.project-card li {
  color: var(--blog-muted);
}

.project-card ul {
  padding-left: 1rem;
  margin-bottom: 0;
}

.search-list-title,
.project-card a,
.post-content a {
  color: var(--blog-accent);
}

/* Homepage phase 2 */
.homepage-shell {
  display: grid;
  grid-template-columns: minmax(220px, 280px) minmax(0, 1fr);
  gap: 4rem;
  align-items: start;
}

.homepage-sidebar {
  position: sticky;
  top: 96px;
}

.homepage-profile-avatar {
  width: 84px;
  height: 84px;
  border-radius: 50%;
  object-fit: cover;
  margin-bottom: 1rem;
}

.homepage-profile-name {
  font-size: 1.8rem;
  font-weight: 700;
  line-height: 1.1;
  color: #0f172a;
}

.homepage-profile-id {
  margin-top: 0.35rem;
}

.homepage-profile-id,
.homepage-profile-intro,
.homepage-profile-email,
.homepage-profile-status {
  color: var(--blog-muted);
}

.homepage-profile-intro,
.homepage-profile-email,
.homepage-profile-status {
  display: block;
  margin-top: 0.9rem;
  line-height: 1.8;
}

.homepage-profile-skills {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
  padding-left: 0;
  list-style: none;
  margin: 1rem 0 0;
}

.homepage-profile-skills li {
  color: var(--blog-accent);
  font-size: 0.92rem;
}

.homepage-profile-skills li::before {
  content: '#';
  margin-right: 0.15rem;
}

.homepage-profile-icons {
  display: flex;
  gap: 0.9rem;
  margin-top: 1rem;
  font-size: 1.05rem;
}

.homepage-main {
  min-width: 0;
}

.homepage-intro {
  margin-bottom: 2rem;
}

.homepage-hero-label {
  font-size: 0.78rem;
  letter-spacing: 0.14em;
  color: var(--blog-accent);
}

.homepage-intro h2 {
  margin: 0.65rem 0 0.85rem;
  font-size: clamp(1.8rem, 3vw, 3.5rem);
  line-height: 1.08;
  color: #0f172a;
}

.homepage-intro p {
  max-width: 760px;
  margin-bottom: 0;
  color: var(--blog-muted);
  font-size: 1.05rem;
  line-height: 1.9;
}

.homepage-post-list {
  display: flex;
  flex-direction: column;
  gap: 2.5rem;
}

.homepage-post-item {
  display: grid;
  grid-template-columns: 200px minmax(0, 1fr);
  gap: 1.5rem;
  align-items: start;
}

.homepage-post-cover img {
  width: 100%;
  aspect-ratio: 1 / 1;
  object-fit: cover;
  border-radius: 24px;
  display: block;
}

.homepage-post-title {
  margin: 0 0 0.8rem;
  font-size: clamp(1.5rem, 2vw, 2rem);
  line-height: 1.2;
}

.homepage-post-title a {
  color: #0f172a;
}

.homepage-post-excerpt,
.homepage-post-excerpt:hover {
  color: var(--blog-text);
  text-decoration: none;
}

.homepage-post-excerpt div {
  line-height: 1.9;
}

.homepage-post-meta {
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem 1rem;
  margin-top: 1rem;
}

#board {
  background: transparent;
  box-shadow: none;
  border-radius: 0;
  border: none;
}

.container.nopadding-x-md {
  max-width: min(1720px, calc(100vw - 48px));
}

#board .container {
  max-width: 100%;
}

#board .container .row > .col-12.col-md-10.m-auto {
  max-width: 100%;
  flex: 0 0 100%;
  padding-left: 0;
  padding-right: 0;
}

@media (max-width: 991.98px) {
  .container.nopadding-x-md {
    max-width: calc(100vw - 32px);
  }

  .homepage-shell {
    grid-template-columns: 1fr;
    gap: 2rem;
  }

  .homepage-sidebar {
    position: static;
  }

  .homepage-intro h2 {
    font-size: 1.8rem;
  }

  .homepage-post-item {
    grid-template-columns: 1fr;
  }

  .homepage-post-cover img {
    max-width: 220px;
  }
}
